import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  detectDateRangePreset,
  SearchTextInput,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { usePnhListFilterState } from '../../../hooks/usePnhListFilterState';
import { usePnhPermissions } from '../../../hooks/usePnhPermissions';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { ReceivingNoteDto } from '../../../services/mh/models';
import { VOUCHER_STATUS_OPTIONS } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { pnhPageLabels } from '../../../constants/pnhPageLabels';
import { MH_PATHS } from '../../../appPaths';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsSchemaListGrid } from '../../../components/list/WmsSchemaListGrid';
import {
  VoucherRowActionMenu,
  type VoucherRowMenuAction,
} from '../../../components/voucher-list/VoucherRowActionMenu';
import { buildPurchasingListToolbar } from '../../../features/mh/purchasingListToolbar';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-mh-pnh';
const PAGE_ID = 'mh-pnh';

const PnhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const { canCreate, canPost, canWrite } = usePnhPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = usePnhListFilterState(LIST_FILTER_SCOPE.pnh);

  const [items, setItems] = useState<ReceivingNoteDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSize] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: ReceivingNoteDto } | null>(null);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);

  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = selection.activeRow;

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getReceivingNotes({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, pnhPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const handlePost = useCallback(async (id: string) => {
    try {
      await purchasingService.postReceivingNote(id);
      dispatchAppToast(dispatch, { message: pnhPageLabels.postSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, pnhPageLabels.postError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const navigateToRow = useCallback((id: string, edit?: boolean) => {
    if (edit) navigate(`${MH_PATHS.nhanHangThem}?editId=${id}`);
    else navigate(MH_PATHS.nhanHangDetail(id));
  }, [navigate]);

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          navigateToRow(row.id);
          break;
        case 'edit':
          if (row.status === 'Draft' && canWrite) navigateToRow(row.id, true);
          break;
        default:
          break;
      }
    },
    [rowMenu, navigateToRow, canWrite],
  );

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow?.status === 'Draft' && canWrite;
  const canPostActive = activeRow?.status === 'Confirmed' && canPost;

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'voucher' as const,
      actions: buildPurchasingListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: refresh,
        onEditConfig: () => setShowSchemaEditor(true),
        canCreate,
        onCreate: () => navigate(MH_PATHS.nhanHangThem),
        canView: canViewActive,
        onView: () => activeRow && navigateToRow(activeRow.id),
        canEdit: canEditActive,
        onEdit: () => activeRow && navigateToRow(activeRow.id, true),
        canApprove: canPostActive,
        onApprove: () => activeRow && handlePost(activeRow.id),
        approveLabel: 'Ghi sổ',
      }),
    }),
    [
      refresh,
      canCreate,
      canViewActive,
      canEditActive,
      canPostActive,
      activeRow,
      navigate,
      navigateToRow,
      handlePost,
    ],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                placeholder="Số phiếu, NCC, đơn MH, kho…"
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-status`}>
              <Select
                label="Trạng thái"
                value={status}
                onChange={e => { setStatus(e.target.value); resetPage(); }}
                options={VOUCHER_STATUS_OPTIONS}
                data-testid={`${TEST_ID}-filter-status`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      fromDate,
      toDate,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
      showTableLoading,
    ],
  );

  const listBody = (
    <WmsSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.receivingNote}
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      viewMobile={viewMobile}
      emptyLabel={pnhPageLabels.empty}
      selection={selection}
      onRowDoubleClick={r => navigateToRow(r.id)}
      onRowOpenActionMenu={({ row, x, y }) => {
        selection.selectActiveRow(row);
        setRowMenu({ x, y, row });
      }}
    />
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: pnhPageLabels.listTitle,
          titleIconClass: 'fas fa-truck-loading',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={pnhPageLabels.listSubtitle}
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
            onPageSizeChange={size => {
              setPageSize(size as ListPageSize);
              setPage(1);
              selection.clearActiveRow();
            }}
          />
        )}
        modals={(
          <>
            <ListUiSchemaEditorModal
              testIdPrefix={TEST_ID}
              catalogKind={LIST_UI_SCHEMA_KIND.receivingNote}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => { setReloadKey(k => k + 1); }}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView
              showEdit={rowMenu?.row.status === 'Draft' && canWrite}
              showViewLedger={false}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default PnhListPage;
